/// <summary>
///
/// </summary>
/// <param name="sender"></param>
/// <param name="e"></param>
[DataEventHandler(tableStr(VendInvoiceDocumentTmp), DataEventType::Inserting)]
public static void VendInvoiceDocumentTmp_onInserting(Common sender, DataEventArgs e)
{
    VendInvoiceDocumentTmp vendInvoiceDocumentTmp = sender as VendInvoiceDocumentTmp;

    VendInvoiceJour vendInvoiceJour;

    select * from vendInvoiceJour
        where vendInvoiceJour.PurchId == vendInvoiceDocumentTmp.PurchNum
        && vendInvoiceJour.InvoiceId == vendInvoiceDocumentTmp.InvoiceNum;

    vendInvoiceDocumentTmp.ETGGRNNumber = vendInvoiceJour.displayPackingSlipId();
}
